import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:8080/api',
});

export const getItems = () => api.get('/items');
export const createItem = (item) => api.post('/items', item);
export const updateItem = (id, item) => api.put(`/items/${id}`, item);
export const deleteItem = (id) => api.delete(`/items/${id}`);
export const getCategories = () => api.get('/categories');
export const createCategory = (category) => api.post('/categories', category);
export const updateCategory = (id, category) => api.put(`/categories/${id}`, category);
export const deleteCategory = (id) => api.delete(`/categories/${id}`);
export const getPurchases = () => api.get('/purchases');
export const createPurchase = (purchase) => api.post('/purchases', purchase);
export const getSales = () => api.get('/sales');
export const createSale = (sale) => api.post('/sales', sale);
export const getBills = () => api.get('/bills');
export const createBill = (bill) => api.post('/bills', bill);
export const getBillPdf = (id) => api.get(`/bills/${id}/pdf`, { responseType: 'blob' });
export const getCompanies = () => api.get('/companies');
export const createCompany = (company) => api.post('/companies', company);
export const updateCompany = (id, company) => api.put(`/companies/${id}`, company);
export const deleteCompany = (id) => api.delete(`/companies/${id}`);
export const getExpenses = () => api.get('/expenses');
export const createExpense = (expense) => api.post('/expenses', expense);
export const getFocs = () => api.get('/focs');
export const createFoc = (foc) => api.post('/focs', foc);
export const getProfitLoss = () => api.get('/reports/profit-loss');
